var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"야, 스승.","JPN":"ねえ、師匠。","ENG":"Hey, Master.","TWN":"喂，師父。"},"stage":{"bg":"COUNTRYROAD","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"발키리가 된다는 건, 어떤 의미냐?","JPN":"ヴァルキリーになるって、どういう意味？","ENG":"So what does it mean to become a Valkyrie?","TWN":"成為女武神……到底代表什麼？"},"stage":{"bg":"COUNTRYROAD","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"넌 그런 것도 모르면서 발키리가 되겠다고 했나?","JPN":"お前はそれも知らずにヴァルキリーになると決めたのか？","ENG":"You said you wanted to become a Valkyrie without even knowing that?","TWN":"你連這個都不知道，就說要成為女武神嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"강한 녀석과 싸울 수만 있으면 돼.","JPN":"強いやつと戦えるならそれでいい。","ENG":"As long as I get to fight someone strong, that's enough.","TWN":"我只要能跟強者戰鬥就夠了。"},"stage":{"bg":"COUNTRYROAD","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"너도 그런 내 성미를 이해하는 줄 알았는데, 아니었어?","JPN":"師匠も私のそういうところを気に入ってると思ったんだけど？","ENG":"I figured that was what you liked about me.","TWN":"我還以為你就是喜歡我這一點呢？"},"stage":{"bg":"COUNTRYROAD","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"세계는 빛으로 창조 되고 어둠에 삼켜져 종말을 맞는다.","JPN":"世界は光で創造され、闇に呑まれて終末を迎える。","ENG":"The world is created by light and meets its end when it is swallowed by darkness.","TWN":"世界由光所創造，最終會被黑暗吞噬而迎來末日。"},"stage":{"bg":"COUNTRYROAD","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"그러니 어둠을 몰아내면 세계는 영원히 존속할 수 있지.","JPN":"ゆえに闇を払えば、世界は永遠に存続できる。","ENG":"So if we drive away the darkness, the world can endure forever.","TWN":"所以只要驅逐黑暗，世界就能永遠存續。"},"stage":{"bg":"COUNTRYROAD","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"발키리가 된다는 건- 종말을 가져오는 어둠에 맞서는 영원한 빛이 된다는 뜻이다.","JPN":"ヴァルキリーになるということは、終末をもたらす闇に立ち向かう、永遠の光になるという意味だ。","ENG":"To become a Valkyrie means becoming an eternal light that stands against the darkness that brings the end.","TWN":"成為女武神—就是成為對抗末日黑暗的永恆之光。"},"stage":{"bg":"COUNTRYROAD","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"흐음...","JPN":"ふーん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"COUNTRYROAD","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"나쁘지 않네. 영원히 싸울 수 있다는 뜻이잖아?","JPN":"悪くないね。永遠に戦えるってことじゃん？","ENG":"Not bad. That means I get to keep fighting forever, right?","TWN":"還不錯嘛。意思就是能永遠戰鬥對吧？"},"stage":{"bg":"COUNTRYROAD","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"싸우는 것 말고, 지킨다는 것에 자부심을 가지도록.","JPN":"戦うことではなく、守るということに誇りを持て。","ENG":"Take pride not in fighting, but in protecting.","TWN":"你別只把重心放在戰鬥上，也試著為守護感到自豪。"},"stage":{"bg":"COUNTRYROAD","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"왜? 사람은 언젠가 죽어. 세계도 그 언젠가가 되면 끝나겠지.","JPN":"なんで？　人間はいつか死ぬし。世界も終わる時が来れば終わるんだよ。","ENG":"Why? People die someday. The world will end someday too.","TWN":"為什麼？人終究會死，世界總有一天也會終結。"},"stage":{"bg":"COUNTRYROAD","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"난 별로, 그런 걸 긍지까지 가져가면서 지키고 싶진 않아.","JPN":"私は別に、誇りを持ってまでそういうものを守りたいと思わないな。","ENG":"I don't care enough about something like that to take pride in protecting it.","TWN":"我可不想抱著什麼自豪感去守護那種東西。"},"stage":{"bg":"COUNTRYROAD","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"하아...","JPN":"はあ……","ENG":"*Sigh...*","TWN":"唉……"},"stage":{"bg":"COUNTRYROAD","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"너 같은 녀석이 어쩌다 대적자로 선택 받은 건지 모르겠군.","JPN":"お前のようなやつがなぜ敵対者として選ばれたのか、理由が分からないな。","ENG":"I don't know how someone like you ended up being chosen as an Antagonist.","TWN":"真不知道你這種傢伙怎麼會被選為敵對者。"},"stage":{"bg":"COUNTRYROAD","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"그런 식으로 말하니까, 폭군이니 검은 역병의 원흉이니 같은 오해를 사는 거다.","JPN":"そういう言い方をするから、暴君だの黒い疫病の元凶だのと誤解されるんだ。","ENG":"Talking like that is exactly why people misunderstand you as a tyrant or the source of the Black Plague.","TWN":"就是因為你這樣講話，才會被誤會成暴君、黑色瘟疫的元兇。"},"stage":{"bg":"COUNTRYROAD","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"아하핫! 마음껏 오해하라고 해.","JPN":"あははっ！　好きなだけ誤解させときなって。","ENG":"Ahaha! Let them misunderstand me all they want.","TWN":"哈哈哈！那就讓他們誤會啊。"},"stage":{"bg":"COUNTRYROAD","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"녀석들이 그렇게 소문을 내준 덕에 세상 강자들이 전부 날 이겨먹겠다고 제 발로 찾아오잖아? 이보다 좋은 기회가 어딨겠어?","JPN":"そうやって噂を広めてくれたおかげで、世界中の強者が私に勝つために自分から来てくれるんだよ？　これ以上おいしいチャンスはなかなかないよ。","ENG":"Thanks to those rumors, every strong fighter in the world keeps showing up right at my doorstep to challenge me. What better opportunity could I ask for?","TWN":"多虧那些傳聞，世界各地的強者全都自己送上門來想打敗我，哪有比這更好的機會？"},"stage":{"bg":"COUNTRYROAD","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"정말이지. 성격 하나는 마왕보다 더 마왕스럽군.","JPN":"まったく。性格だけは魔王よりも魔王らしいな。","ENG":"Honestly. Your personality is more Demon Lord-like than an actual Demon Lord's.","TWN":"真是的，你這個性比魔王還像魔王。"},"stage":{"bg":"COUNTRYROAD","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"오히려 그 편이 낫지. 마음에도 없는 정의를 논할 바엔 마왕이 되는 거 말이야.","JPN":"かえってそのほうがましかも。心にもない正義を論ずるぐらいなら、魔王になったほうがいい。","ENG":"That's even better. If the alternative is pretending to care about justice I don't believe in, I'd rather become a Demon Lord.","TWN":"這樣反而更好。與其談論那些虛假的正義，不如乾脆當魔王。"},"stage":{"bg":"COUNTRYROAD","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"그렇게 되면, 너하고도 진심으로 겨뤄볼 수 있을 테고.","JPN":"そうしたら、師匠とも本気で戦えるだろうし。","ENG":"If that happens, I'd finally be able to fight you seriously too.","TWN":"這樣一來……也能和你痛痛快快打一場。"},"stage":{"bg":"COUNTRYROAD","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"...웃기지 마라.","JPN":"……ふざけるな。","ENG":"...Don't be ridiculous.","TWN":"……別開玩笑了。"},"stage":{"bg":"COUNTRYROAD","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"넌 발키리가 될 거다. 마왕이 아니라.","JPN":"お前はヴァルキリーになる。魔王ではなく。","ENG":"You're going to become a Valkyrie. Not a Demon Lord.","TWN":"你會成為女武神，不是魔王。"},"stage":{"bg":"COUNTRYROAD","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"아하하, 왜? 마왕이 된 나랑 싸우면 질까 봐 무서워?","JPN":"あはは、何で？　魔王になった私と戦ったら負けそうで怖い？","ENG":"Ahaha, why? Afraid you'd lose if I became a Demon Lord?","TWN":"哈哈，怎麼了？你怕會打輸成為魔王的我嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"나와 한 맹세를 잊었나?","JPN":"私との誓いを忘れたか？","ENG":"Have you already forgotten the oath you made with me?","TWN":"你忘了和我立下的誓言嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_PRIDE"}}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"내가 대적자를 가르치는 건 마왕에 맞서기 위함이다. 마왕이 되기 위해서가 아니라!","JPN":"私が敵対者を育てるのは魔王に立ち向かうためだ。魔王にするためではない！","ENG":"I teach the Antagonist so she can stand against the Demon Lord. Not so she can become one!","TWN":"我教導敵對者是為了對抗魔王，不是讓你成為魔王！"},"stage":{"bg":"COUNTRYROAD","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"흥, 그깟 맹세 개나 주라지. 난 더 재미있는 쪽이 좋거든.","JPN":"ふん、そんな誓い、どうでもいいよ。私は面白ければ、そっちのほうがいい。","ENG":"Hmph, you can shove that oath. I prefer whichever path sounds more interesting.","TWN":"哼，誰要理那種誓言。我只選更有趣的那條路。"},"stage":{"bg":"COUNTRYROAD","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"하아.","JPN":"はあ。","ENG":"*Sigh*","TWN":"唉。"},"stage":{"bg":"COUNTRYROAD","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"시련?","JPN":"試練？","ENG":"A trial?","TWN":"試煉？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"그래. 발키리가 되는 마지막 시험으로서, 심연이 보낸 첫 번째 종말을 막는 거다.","JPN":"ああ。ヴァルキリーになる最後の試練。深淵が送り出した初めての終末を食い止めるんだ。","ENG":"Yes. As your final trial to become a Valkyrie, you must stop the first apocalypse sent by the Abyss.","TWN":"對。作為成為女武神的最後試煉，阻止深淵派來的第一個末日。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"이 세계에 강림한 마왕을 상대하는 거지.","JPN":"この世界に降臨した魔王と戦うことになる。","ENG":"You'll be facing the Demon Lord who has descended upon this world.","TWN":"也就是對抗降臨於這個世界的魔王。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"마왕을 죽인다라. 재밌겠네.","JPN":"魔王を殺すのか。面白そう。","ENG":"Killing a Demon Lord, huh. Sounds fun.","TWN":"殺掉魔王啊……挺有意思的。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"자만하지 말고 끝까지 신중하게 행동해라.","JPN":"自惚れず最後まで慎重に行動しろ。","ENG":"Don't be arrogant. Stay cautious until the very end.","TWN":"別太自滿，直到最後都要謹慎行動。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_SERIOUS"},"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"클리포트 게임의 규칙상, 지금부터 난 너희들의 일에 개입할 수 없으니까.","JPN":"クリフォトゲームのルール上、今から私はお前たちに干渉できない。","ENG":"Under the rules of the Qliphoth Game, I can't intervene in your affairs from this point on.","TWN":"依照逆卡巴拉遊戲的規則，從現在開始，我無法再介入你們之間。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"스승의 도움은 필요 없어. 난 내 심복 둘만 있으면 충분해.","JPN":"師匠の助けなんかいらないよ。私は自分の部下2人がいれば十分。","ENG":"I don't need your help, Master. As long as I have my two lieutenants, that's enough.","TWN":"我不需要師父幫忙，只要帶上兩個心腹就夠了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"그 마왕 녀석, 이름은 뭐지?","JPN":"その魔王ってやつ、名前は何ていうの？","ENG":"That Demon Lord... what's their name?","TWN":"那個魔王……叫什麼名字？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"...암군.","JPN":"……暗君。","ENG":"...Ignorant Monarch.","TWN":"……暗君。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"타기리온이다.","JPN":"タギリオンだ。","ENG":"Thagirion.","TWN":"塔基里翁。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"헉... 헉...","JPN":"はあ……はあ……","ENG":"*Huff...* *Huff...*","TWN":"呼……呼……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"인간치곤 제법이군요. 제가 만든 아공간에서 30일을 쉬지 않고 싸우며 버티다니.","JPN":"人間にしてはなかなかやりますね。私が作った亜空間で30日を休まず戦い続けられるとは。","ENG":"Impressive for a human. To keep fighting for thirty days without rest inside the domain I created.","TWN":"以人類來說還真是了不起。在我創造的亞空間裡，連續戰鬥30天都沒休息還撐得住。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"정직하게 힘으로만 승부를 봤다면, 그렇게 추하게 쓰러져 있는 건 당신이 아니라 저였을지도 모르겠어요.","JPN":"真面目に力だけで勝負していたら、そうやってみっともなく倒れていたのは私だったかもしれません。","ENG":"If this had been a straightforward contest of strength alone, the one lying there in such a miserable state might have been me instead of you.","TWN":"如果是光憑力量一決勝負，現在狼狽倒下的恐怕是我而不是你了。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"흥, 언니 언니 하더니 자기 자매를 전부 방패막이에 자폭용으로 쓸 줄이야.","JPN":"ふん、お姉ちゃんお姉ちゃん言っといて、自分の姉妹を全部盾にしたり自爆させたりするなんてね。","ENG":"Hmph. Calling everyone \\"sister,\\" yet you used every last one of them as shields and suicide bombs.","TWN":"哼，一口一個姐姐，結果居然把自己的姐妹全都拿來當盾牌和自爆。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"대체 넌, 그 빌어먹을 언니가 몇이나 더 있는 거냐?","JPN":"いったい、そのくそったれお姉ちゃんはあと何人いるわけ？","ENG":"Just how many of those damn sisters do you even have?","TWN":"你到底還有多少個該死的姐姐？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"딱, 제가 거쳐온 세상의 수만큼 모았답니다.","JPN":"私が経験してきた世界の数だけです。","ENG":"Exactly as many as the number of worlds I've passed through.","TWN":"正好跟我經歷過的世界數量一樣多。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"모든 세상엔 저의 언니가 있거든요. 당신의 세계도 마찬가지고요.","JPN":"すべての世界には私のお姉ちゃんがいるんです。あなたの世界も例外ではありません。","ENG":"Every world has my sister in it. Yours is no exception.","TWN":"每個世界裡，都有我的姐姐。你的世界也一樣。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"쿨럭...","JPN":"ゴホッ……","ENG":"*Cough...*","TWN":"咳……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_DESPAIR"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_WATER"},{"id":"L10_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"당신이 제 아무리 강한 대적자라 해도, 결국 인간의 육신에 갇힌 이상 한계는 명확하죠.","JPN":"あなたがいくら強い敵対者でも、結局人間の肉体に宿る以上、限界は決まっています。","ENG":"No matter how strong an Antagonist you are, as long as you're bound to a human body, your limits are obvious.","TWN":"不管你再怎麼強，終究被困在人類的肉體，也有明確的極限。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그런 망가진 몸으로 질질 끌어봐야 승산은 없어요.","JPN":"そんなボロボロの体で時間を稼いでも、あなたに勝ち目はありませんよ。","ENG":"Dragging around a body that broken won't change your chances.","TWN":"拖著這副破爛的身體繼續撐，也沒有勝算。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"아니.","JPN":"違うね。","ENG":"No.","TWN":"不。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"이기진 못해도, 난 지는 싸움은 하지 않아.","JPN":"たとえ勝てなくたって、私は負ける戦いはしない。","ENG":"Even if I can't win, I never fight a losing battle.","TWN":"就算贏不了，我也不會打輸的仗。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_SERIOUS"},"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FIRE_04"},{"id":"L17_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"당신이 가진 인간의 몸은 그 정도의 불꽃을 감당할 수 없어요.","JPN":"あなたの持つ人間の体は、その程度の炎でも耐えられません。","ENG":"Your human body can't withstand a flame like that.","TWN":"你的人類軀體無法承受那種火焰。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"발키리의 시련 때문에, 여기서 자기 목숨을 태울 셈인가요?","JPN":"ヴァルキリーの試練のために、ここで自分の命を燃やすつもりですか？","ENG":"Are you planning to burn your life away here because of the Valkyrie's trial?","TWN":"你打算為了女武神的試煉，在這裡燃盡自己的生命嗎？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"시련 따윈 까라고 해, 타기리온.","JPN":"試練なんてクソ食らえだ、タギリオン。","ENG":"To hell with the trial, Thagirion.","TWN":"我才不管什麼試煉，塔基里翁。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"넌 여기서... 나와 함께 재가 되어 사라진다.","JPN":"あんたはここで……私と一緒に灰になって消えるんだよ。","ENG":"Right here... You and I are turning to ash together.","TWN":"你就和我一起……在這裡化為灰燼吧。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE"},{"id":"L24_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"...당신의 마지막 불꽃은 충분히 강했어요.","JPN":"……あなたの最後の炎は十分強いものでした。","ENG":"Your final flame was strong enough.","TWN":"……你最後的火焰，已經夠強了。"},"stage":{"bg":"SKY_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"대적자.","JPN":"敵対者。","ENG":"Antagonist.","TWN":"敵對者。"},"stage":{"bg":"SKY_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"...하... 망할...","JPN":"……はあ……くそ……","ENG":"...*Sigh...* Damn it...","TWN":"……哈……該死……"},"stage":{"bg":"SKY_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"너... 본체가... 아니었나...?","JPN":"あんた……本体じゃ……なかったの……？","ENG":"You... weren't the original...?","TWN":"你……不是本體嗎……？"},"stage":{"bg":"SKY_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"제 몸은 인형이에요.","JPN":"私の体は人形です。","ENG":"My body is a doll.","TWN":"我的身體只是人偶。"},"stage":{"bg":"SKY_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그리고 당신도 알다시피, 인형은 대체가능한 소모품일 뿐이니까요.","JPN":"そしてあなたも知っている通り、人形は替えの利く消耗品にすぎません。","ENG":"And as you know, dolls are nothing more than replaceable consumables.","TWN":"而你也知道，人偶不過是可以替換的消耗品。"},"stage":{"bg":"SKY_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"제 왕좌를 노리던 늑대는 이미 죽였습니다.","JPN":"私の玉座を狙っていたオオカミはすでに殺しました。","ENG":"The Wolf who sought my throne is already dead.","TWN":"我已經殺了那個盯上我王座的狼。"},"stage":{"bg":"SKY_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"클리포트 게임은 끝났어요.","JPN":"クリフォトゲームは終わったのです。","ENG":"The Qliphoth Game is over.","TWN":"逆卡巴拉遊戲結束了。"},"stage":{"bg":"SKY_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"...관심 없어.","JPN":"……興味ないね。","ENG":"...Don't care.","TWN":"……我不在乎。"},"stage":{"bg":"SKY_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"...게임 같은 거...처음부터 이기든 지든... 관심 없었다고.","JPN":"……ゲームなんか……最初から勝とうが負けようが……どうでもよかったんだ。","ENG":"...This whole game... whether I won or lost... I never cared from the start.","TWN":"從一開始……我就不在乎什麼遊戲……什麼輸贏。"},"stage":{"bg":"SKY_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"...싸울 수만 있으면 그걸로 족하다- 그게 당신의 유언인가요?","JPN":"……戦えるならそれでいい……それがあなたの遺言ですか？","ENG":"So as long as you got to fight, that's enough. Is that your final wish?","TWN":"……只要能戰鬥就夠了—這就是你的遺言嗎？"},"stage":{"bg":"SKY_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_RED","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"대적자? 그게 뭔데?","JPN":"敵対者？　何なのそれ。","ENG":"Antagonist? What's that?","TWN":"敵對者？那是什麼？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"세피로트 나무라는 존재가 구축한 일종의 면역 시스템이다.","JPN":"セフィロトという存在が構築した、一種の免疫システムだな。","ENG":"It's a kind of immune system established by the Tree of Sephiroth.","TWN":"那是一種由生命樹構築的免疫系統。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"곧 다가올 종말을 감지한 세계가, 그것에 대적할 항체로서 널 고른 거지.","JPN":"まもなくやってくる終末を感知した世界が、それに立ち向かうための抗体としてお前を選んだんだ。","ENG":"When the world senses the coming apocalypse, it selects you as an antibody to oppose it.","TWN":"當世界察覺即將到來的末日，就會選擇你作為對抗它的抗體。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"날 보자마자 덤벼들 정도로 막무가내일 줄은 몰랐다만... 힘은 제법 쓸만하군.","JPN":"私を見るなり飛びかかってくるほど強引なやつだとは思わなかったが……腕はなかなかいい。","ENG":"I didn't expect you to be reckless enough to attack me the moment you saw me... but your strength is quite usable.","TWN":"沒想到你一見到她就直接開打……不過力量倒還不錯。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"...흥.","JPN":"……ふん。","ENG":"...Hmph.","TWN":"……哼。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"세상을 지키는 일 같은 건 관심 없어. 난 싸울 수만 있으면 딴 건 아무래도 좋아.","JPN":"世界を守ることなんて興味ないね。私は戦えるなら他はどうでもいい。","ENG":"I'm not interested in protecting the world. As long as I get to fight, nothing else matters.","TWN":"我對守護世界沒興趣。只要能戰鬥，其他都無所謂。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"네가 원하느냐 원치 않느냐는 중요하지 않다.","JPN":"お前が望むか望まないかは重要ではない。","ENG":"Whether you want it or not doesn't matter.","TWN":"你願不願意不重要。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"한 번 정해진 운명은 바뀌지 않으니까.","JPN":"一度決まった運命は変わらないからな。","ENG":"Once fate is decided, it cannot be changed.","TWN":"既定的命運，是不會改變的。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"누가 그딴 걸 멋대로 정하는데?","JPN":"誰がそんなもの勝手に決めるわけ？","ENG":"Who decides something like that on their own?","TWN":"這是誰決定的？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_HATE"},"C":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"그런 건 자연스레 알게 될 거다. 네가 종말을 막아내고 발키리의 자격을 증명한다면 말이야.","JPN":"それは自然と分かるようになる。お前が終末を食い止め、ヴァルキリーの資格を証明できればな。","ENG":"You'll come to understand that naturally. If you stop the apocalypse and prove yourself worthy of becoming a Valkyrie.","TWN":"當你阻止末日、證明自己有成為女武神資格的時候，你自然會知道。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"...여긴 어디지?","JPN":"……ここはどこ？","ENG":"...Where am I?","TWN":"……這裡是哪裡？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DASH_ANAP_NULL_QM","text":{"KOREA":"이곳은 당신의 말로랍니다.","JPN":"ここはあなたの末路です。","ENG":"This is your resting place.","TWN":"用你的話來說，"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DASH_ANAP_NULL_QM","text":{"KOREA":"저승의 문턱 같은 곳이죠. 여기서 하는 얘긴 누구도 엿듣거나 기억하지 못할 거에요.","JPN":"冥府の入口のような場所です。ここでの話は誰も盗み聞いたり、記憶することができません。","ENG":"A place like the threshold of the afterlife. No one will overhear or remember what is said here.","TWN":"是類似陰間的地方。在這裡說的話，不會被任何人偷聽，也不會被記住。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"흥.","JPN":"ふん。","ENG":"Hmph.","TWN":"哼。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"죽으면 그냥 죽는 거지. 별 구차한 공간이 다 있군.","JPN":"死ねばそれで終わりでしょ。くだらない場所もあるもんだね。","ENG":"If you die, you die. What a pathetic place.","TWN":"死了就死了，還搞這種多餘的地方。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DASH_ANAP_NULL_QM","text":{"KOREA":"당신은 이용 당했어요.","JPN":"あなたは利用されたんです。","ENG":"You were used.","TWN":"你被利用了。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"...뭐?","JPN":"……は？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"너, 대뜸 무슨 소릴 하는 거야?","JPN":"いきなり何の話？","ENG":"What are you talking about all of a sudden?","TWN":"你沒頭沒腦地說什麼？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DASH_ANAP_NULL_QM","text":{"KOREA":"발키리는 당신이 자신과 같은 존재가 될 수 있다고 말했겠지만... 사실 당신은 마왕으로 전락할 수 밖에 없는 운명을 타고 났어요.","JPN":"ヴァルキリーはあなたが自分と同じ存在になれると言っていましたが……本当は、あなたは魔王に身を落とすしかない運命に生まれました。","ENG":"The Valkyrie may have told you that you could become something like her... but in truth, you were born with a fate that could only lead you to fall into becoming a Demon Lord.","TWN":"女武神或許告訴過你，你有機會成為像她一樣的存在……但其實，你天生就只能走向墮落為魔王的命運。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_NULL_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DASH_ANAP_NULL_QM","text":{"KOREA":"모든 대적자는 마왕이 되는 최후를 맞게 되거든요.","JPN":"すべての敵対者は最後に魔王になるんです。","ENG":"Every Antagonist eventually meets the end of becoming a Demon Lord.","TWN":"所有敵對者，最後都會成為魔王。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"...대적자는 세상을 구하기 위한 존재잖아. 내가 왜 그딴 헛소릴 믿을 거라고 생각하지?","JPN":"……敵対者は世界を救うための存在なんでしょ。私がそんなでたらめを信じると思う？","ENG":"...Antagonists exist to save the world. Why would I believe nonsense like that?","TWN":"……敵對者不是為了拯救世界的存在嗎？你以為我會信這種鬼話？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DASH_ANAP_NULL_QM","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"DASH_ANAP_NULL_QM","text":{"KOREA":"마왕은, 세계라는 한 그루의 나무가 자신의 양분을 모두 쏟아내서 만든 결실이에요.","JPN":"魔王は、世界という1本の木が己の養分をすべて注ぎ込んで育てた実なのです。","ENG":"A Demon Lord is the fruit produced when a single tree called the world pours all its nutrients into it.","TWN":"魔王，是這棵世界樹傾盡所有養分所結出的果實。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DASH_ANAP_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"DASH_ANAP_NULL_QM","text":{"KOREA":"그렇게 맺어진 결실을 늑대란 존재가 나타나 먹어 치우는 것까지가, 신이 세계를 만든 목적이죠.","JPN":"そうやって実った結実を、オオカミという存在が現れて食らい尽くす。そこまでが神が世界を作った目的です。","ENG":"And the purpose for which god created the world was for the being called the Wolf to appear and devour that fruit.","TWN":"而那顆果實，最終會被狼吞噬。這正是神創造世界的目的。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DASH_ANAP_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"마왕이... 늑대에게 먹이려고 만들어진 존재라고?","JPN":"魔王が……オオカミに食べられるために作られた存在だって？","ENG":"A Demon Lord... was created just to be eaten by the Wolf?","TWN":"魔王……是為了餵飽狼而存在？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DASH_ANAP_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"DASH_ANAP_NULL_QM","text":{"KOREA":"신은 아주 큰 힘을 모으고 있거든요. 늑대는 그걸 흡수하기 위한 수단이죠.","JPN":"神はとても大きい力を集めているんです。オオカミはそれを吸収するための手段ですね。","ENG":"God is gathering an immense power. The Wolf is merely a means to absorb it.","TWN":"神正在累積極為龐大的力量，而狼就是用來吸收那股力量的工具。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DASH_ANAP_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"...뭐가 됐든. 난 실패했어. 그 늑대란 녀석도 죽었고.","JPN":"……とにかく、私は失敗したんだよ。そのオオカミとやらも死んだし。","ENG":"...Whatever. I failed anyway. And that Wolf is dead too.","TWN":"……無論如何，我已經失敗了。那隻狼也死了。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DASH_ANAP_NULL_QM","text":{"KOREA":"그렇다면 신은 그걸 성공할 때까지 되풀이할 뿐이에요.","JPN":"なら、神は成功するまでそれを繰り返すまでです。","ENG":"Then god will simply repeat it until it succeeds.","TWN":"那麼神就會不斷重來，直到成功為止。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DASH_ANAP_NULL_QM","text":{"KOREA":"신에겐 세피로트 나무라는, 세상을 몇 번이고 만들어낼 수 있는 권한이 있거든요.","JPN":"神はセフィロトという、何度でも世界を生み出せる権限を持っていますから。","ENG":"God has the authority called the Tree of Sephiroth, which allows the world to be created again and again.","TWN":"因為神擁有生命之樹，擁有可以一遍又一遍重塑世界的權限。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_NULL_QM","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"세피로트 나무라는 존재가 구축한 일종의 면역 시스템이다.","JPN":"セフィロトという存在が構築した、一種の免疫システムだな。","ENG":"It's a kind of immune system established by the Tree of Sephiroth.","TWN":"那是一種由生命樹構築的免疫系統。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"곧 다가올 종말을 감지한 세계가, 그것에 대적할 항체로서 널 고른 거지.","JPN":"まもなくやってくる終末を感知した世界が、それに立ち向かうための抗体としてお前を選んだんだ。","ENG":"When the world senses the coming apocalypse, it selects you as an antibody to oppose it.","TWN":"當世界察覺即將到來的末日，就會選擇你作為對抗它的抗體。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"흥, 뭐야.","JPN":"ふ～ん、何だ。","ENG":"Hmph. So what?","TWN":"哼，原來如此。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"스승은 처음부터 다 알고 있으면서 날 속였단 건가?","JPN":"師匠は最初から全部知ってて私を騙したってこと？","ENG":"Does that mean Master knew everything from the start and still deceived me?","TWN":"師父一開始就全都知道，還騙了我嗎？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DASH_ANAP_NULL_QM","text":{"KOREA":"발키리 역시, 신의 뜻에 이용당하는 꼭두각시일 뿐이에요.","JPN":"ヴァルキリーもまた、神の意志に利用される操り人形に過ぎません。","ENG":"The Valkyrie too is nothing more than a puppet being used by god.","TWN":"女武神也不過是被神利用的傀儡。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DASH_ANAP_NULL_QM","text":{"KOREA":"그녀는 자신이 대적자를 발키리의 길로 인도할 수 있을 거라 믿고 있지만... 사실 그녀가 성심껏 가르친 대적자는 더 강한 마왕으로 전락할 뿐이거든요.","JPN":"彼女は自分が敵対者をヴァルキリーの道へ導けると信じていますが……実は、彼女が誠心誠意育てた敵対者は、より強力な魔王となるだけなのです。","ENG":"She believes she can guide the Antagonist onto the path of a Valkyrie... but in truth, the Antagonist she teaches with all her heart only ends up falling into becoming an even stronger Demon Lord.","TWN":"她以為自己能引導敵對者走向女武神之路……但實際上，她傾心教導的敵對者，只會成為更強的魔王。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"...바보네.","JPN":"……バカだね。","ENG":"...What an idiot.","TWN":"……真愚蠢。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"그렇게 노력해놓고 신에게 빼앗기기만 하는 운명이라니.","JPN":"あんなに頑張っても、神に奪われるだけってこと？","ENG":"After all that effort, she just has everything taken away by god?","TWN":"那麼努力，最後卻只是被神奪走一切？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DASH_ANAP_NULL_QM","text":{"KOREA":"머잖아 그녀도 자신이 이용 당했다는 걸 깨닫게 되겠지만... 그럼에도 신이 그녀의 운명을 쥐고 있는 이상, 그 굴레에서 벗어날 순 없겠죠.","JPN":"まもなく彼女も自分が利用されていたことに気づくでしょうけど……それでも、神が彼女の運命を握っている以上、その運命から逃れることはできません。","ENG":"Soon she'll realize that she was used too... but as long as god holds her fate in its grasp, she won't be able to escape that cycle.","TWN":"她很快也會察覺自己被利用……但只要神仍掌握她的命運，她就無法擺脫這個輪迴。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"그래서? 내 앞에 나타나 그런 말을 지껄이는 이유가 뭐지?","JPN":"それで？　私の前に現れてそんな話をほざく理由は何？","ENG":"So what? Why did you show up in front of me just to say all this?","TWN":"所以呢？你特地出現在我面前說這些，是為了什麼？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DASH_ANAP_NULL_QM","text":{"KOREA":"모든 것이 순리대로 흘러갈 기회를 당신에게 주고 싶어요.","JPN":"すべてを理に適うようにするチャンスをあなたに与えたいのです。","ENG":"I want to give you a chance for everything to proceed according to its natural course.","TWN":"我想給你一個讓一切順其自然的機會。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DASH_ANAP_NULL_QM","text":{"KOREA":"대적자로서 죽는 대신, 본래 주어진 마왕의 운명을 따르는 거죠.","JPN":"敵対者として死ぬ代わりに、本来与えられた魔王の運命に従うのです。","ENG":"Instead of dying as an Antagonist, you can follow the Demon Lord's fate that was originally given to you.","TWN":"不以敵對者的身分死去，而是順從你原本被賦予的、魔王的命運。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"내가 타기리온에게 가는 길을 열기 위해, 목숨을 바친 짐승 둘이 있어.","JPN":"私がタギリオンにたどり着くまでの道を開くために命を捧げた獣が2人いるんだ。","ENG":"There are two beasts who gave their lives to open the path for me to reach Thagirion.","TWN":"為了替我開創通往塔基里翁的路，有兩隻野獸犧牲了性命。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":"뱀파이어와 늑대인간. 그 두 녀석은 어떻게 되지?","JPN":"ヴァンパイアとライカンスロープ。あの2人はどうなるの？","ENG":"The vampire and the lycanthrope. What will happen to them?","TWN":"吸血鬼和狼人……他們會怎樣？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DASH_ANAP_NULL_QM","text":{"KOREA":"그들은 당신과 또 한번 만날 거에요. 하지만 이번엔 대적자가 아닌 마왕이 된 폭군을 찾아오겠죠.","JPN":"彼らはもう一度あなたに出会います。ですが、今回は敵対者ではなく魔王になった暴君に会いに来ることになるでしょう。","ENG":"You will meet them once again. But this time, they will come looking for the tyrant who became a Demon Lord instead of an Antagonist.","TWN":"你們會再見面的。但那時候，他們將面對的不再是敵對者，而是成為魔王的暴君。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NONAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NONAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NAME","text":{"KOREA":"넌 발키리가 될 거다. 마왕이 아니라.","JPN":"お前はヴァルキリーになる。魔王ではなく。","ENG":"You're going to become a Valkyrie. Not a Demon Lord.","TWN":"你會成為女武神，不是魔王。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"narration","speaker":null,"text":{"KOREA":"그래.","JPN":"分かったよ。","ENG":"Yeah.","TWN":"是啊。"},"stage":{"bg":"BLACK","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"narration","speaker":null,"text":{"KOREA":"애초에 발키리 같은 건 어울리지도 않았어.","JPN":"そもそもヴァルキリーなんて似合わなかったんだ。","ENG":"Being a Valkyrie never suited me from the start.","TWN":"從一開始女武神就不適合我。"},"stage":{"bg":"BLACK","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"내겐 정의도, 숭고함도 없으니까.","JPN":"私には正義も、崇高さもないから。","ENG":"I don't have justice. I don't have nobility.","TWN":"我沒有正義，也沒有什麼崇高的信念。"},"stage":{"bg":"BLACK","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"그 녀석과는 처음부터... 싸우고 싶었을 뿐이라고.","JPN":"あいつとは最初から……戦いたかっただけなんだ。","ENG":"From the very beginning... all I ever wanted was to fight her.","TWN":"從一開始……我就只是想和那傢伙戰鬥而已。"},"stage":{"bg":"BLACK","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"아하하하, 실망시키지 않는다니까.","JPN":"あははは、やはり期待どおりじゃ。","ENG":"Ahahaha, you never disappoint.","TWN":"哈哈哈，我就知道你不會讓我失望。"},"stage":{"bg":"SWORDGRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_03"},{"id":"L6_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"내 검을 피하지 않고 맞부딪힐 수 있는 건... 역시 너뿐이라고!","JPN":"妾の剣を避けずに受け止められるのは……やはり其方だけじゃ！","ENG":"The only one who can clash blades with mine head-on without dodging... is you, after all!","TWN":"能正面接下我這把劍的……果然只有你！"},"stage":{"bg":"SWORDGRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"아스모데우스.","JPN":"アスモデウス。","ENG":"Asmodeus.","TWN":"阿斯蒙蒂斯。"},"stage":{"bg":"SWORDGRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"자신을 불태우면서까지 무리하고 있군.","JPN":"己を燃やしてまで無理をしているんだな。","ENG":"You're pushing yourself too far, even burning yourself up to do it.","TWN":"你是在燃燒自己強撐啊。"},"stage":{"bg":"SWORDGRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"하지만 내 힘이 완전하지 못하다 해도, 이젠 나를 뛰어넘을 수 없을 거다.","JPN":"だが、私の力が完全ではないといえ、もう私を超えることはできないだろう。","ENG":"Even if my power isn't yet complete, you won't surpass me anymore.","TWN":"不過就算我的力量還不完整，你也已經無法超越我了。"},"stage":{"bg":"SWORDGRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"힘이 아니라 허세만 늘었나?","JPN":"成長したのは力ではなく虚勢か？","ENG":"Have you grown stronger, or just louder?","TWN":"力量沒變強，倒是會虛張聲勢了啊？"},"stage":{"bg":"SWORDGRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"막는 것만으로도 버거운 주제에!","JPN":"防ぐだけで精一杯のくせに！","ENG":"You can barely manage to block my attacks!","TWN":"光擋下來就已經很吃力了吧！"},"stage":{"bg":"SWORDGRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"내 발을 묶으면서까지 타기리온을 돕는 이유가 뭐지?","JPN":"私の足止めをしてまでタギリオンに手を貸す理由は何だ？","ENG":"Why are you helping Thagirion by tying me down here?","TWN":"你為什麼要幫塔基里翁拖住我？"},"stage":{"bg":"SWORDGRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"네 놈과 겨룰 수만 있다면, 과정은 아무래도 상관없어.","JPN":"其方と勝負できるなら、過程はどうでも良い。","ENG":"As long as I can fight you, the process doesn't matter.","TWN":"只要能和你戰鬥，無論是什麼過程都無所謂。"},"stage":{"bg":"SWORDGRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"하물며 그게 멍청한 암군의 계획이라 해도 말이야...!","JPN":"ましてやそれが愚かな暗君の計画だとしてもじゃ……！","ENG":"Even if it means going along with that foolish Ignorant Monarch's plan...!","TWN":"就算是那個愚蠢暗君的計畫也一樣……！"},"stage":{"bg":"SWORDGRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SWORDGRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"정말 이 악연을 끝내고 싶은 거라면...","JPN":"本当にこの腐れ縁を終わらせたいのなら……","ENG":"If you truly wanted to end this ill-fated bond between us...","TWN":"如果你真的想結束這段孽緣……"},"stage":{"bg":"SWORDGRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"왜 내가 타기리온의 실에 묶였을 때를 노리지 않았지?","JPN":"なぜ私がタギリオンの糸に縛られていた時を狙わなかった？","ENG":"Why didn't you strike when I was bound by Thagirion's threads?","TWN":"為什麼不在我被塔基里翁的線束縛時動手？"},"stage":{"bg":"SWORDGRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"잊었어? 난 일방적인 것보다, 치고 받는 쪽을 좋아하거든.","JPN":"忘れたのか？　妾は一方的に攻めるよりやり合うほうが好きなのじゃ。","ENG":"Did you forget? I prefer a real exchange over something one-sided.","TWN":"你忘了嗎？我不喜歡一面倒的戰鬥，更喜歡勢均力敵互相廝殺。"},"stage":{"bg":"SWORDGRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"네놈이 실에 조종 당해 늑대를 죽여버리기라도 했다면, 제 발로 여기까지 찾아오지도 않았을 테고. 안 그래?","JPN":"其方が糸に操られてオオカミを殺していたら、自らの意志でここまで来ることもなかったであろう？","ENG":"If you had been controlled by those threads and killed the Wolf, you wouldn't have come all the way here on your own, would you?","TWN":"要是你被線操控去殺了那隻狼，你也不會自己走到這裡來吧？對吧？"},"stage":{"bg":"SWORDGRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SWORDGRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"넌 예나 지금이나, 변하지 않는군.","JPN":"お前は昔も今も変わらないな。","ENG":"You really haven't changed at all.","TWN":"你還是一樣，從來都沒變。"},"stage":{"bg":"SWORDGRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"와라.","JPN":"来い。","ENG":"Come.","TWN":"來吧。"},"stage":{"bg":"SWORDGRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"물러서지 않을 테니, 이번에야말로 끝장을 보자.","JPN":"全力でいく。今度こそ決着をつけよう。","ENG":"I won't step back. This time, we settle this for good.","TWN":"我不會退縮，這一次就徹底做個了結。"},"stage":{"bg":"SWORDGRAVE","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};